func runTrace(t *testing.T, dir string) {
	t.Helper()
	raw, meta := readTrace(t, dir)

	if len(raw) != meta.TotalBytes {
		t.Errorf("total bytes %d, expected %d", len(raw), meta.TotalBytes)
	}

	verifyFrames(t, raw, meta)
	verifyTranscriptHashes(t, raw, meta)
	verifySessionID(t, raw, meta)
}
